/**
 * OpenRFID Simulator — Hopeland Protocol Server & Bridge
 * ========================================================
 * Implements:
 *  1. A WebSocket control server (port 9098) to bridge with the React simulator frontend.
 *  2. Hopeland UDP Multicast Discovery (230.1.1.116:9091) controlled dynamically by UI state.
 *  3. Hopeland TCP Command Server (9090) that forwards tag reads generated by the UI.
 *
 * This ensures that starting/stopping the simulator or changing simulation settings
 * (such as 30s intervals or rate limits) in the UI directly controls the physical emulator.
 */

const dgram = require('dgram');
const net   = require('net');
const os    = require('os');
const ws    = require('ws');

// ── Configuration ─────────────────────────────────────────────────────────────
const MULTICAST_GROUP   = '230.1.1.116';
const MULTICAST_PORT    = 9091;
const TCP_PORT          = 9090;
const WS_PORT           = 9098;
const ANNOUNCE_INTERVAL = 2000;
const READER_ADDR       = 0x02;

const CMD = {
  GET_EPC:    0x10,
  STOP:       0xFF,
  TAG_DATA:   0x12,
};

const KNOWN_FRAMES = [
  { data: [0xAA, 0x02, 0xFF, 0x00, 0x00],                           crc: [0xA4, 0x0F] },
  { data: [0xAA, 0x02, 0x10, 0x00, 0x05, 0x01, 0x01, 0x02, 0x00, 0x06],     crc: [0x80, 0xE4] },
];

// ── CRC16 ─────────────────────────────────────────────────────────────────────
function calcCRC(frameBytes) {
  const data = Array.isArray(frameBytes) ? frameBytes.slice(1) : Array.from(frameBytes).slice(1);
  let crc = 0x0000;
  for (const byte of data) {
    crc ^= (byte << 8);
    for (let i = 0; i < 8; i++) {
      crc = (crc & 0x8000) ? (((crc << 1) & 0xFFFF) ^ 0x8005) : ((crc << 1) & 0xFFFF);
    }
  }
  return [(crc >> 8) & 0xFF, crc & 0xFF];
}

// ── Frame Builders ────────────────────────────────────────────────────────────
function buildFrame(cmd, data) {
  const frameNoCheck = [0xAA, READER_ADDR, cmd, 0x00, data.length, ...data];
  const crc = calcCRC(frameNoCheck);
  return Buffer.from([...frameNoCheck, ...crc]);
}

function ackOk(cmd) {
  return buildFrame(cmd, [0x00]);
}

function buildTagFrame(epcHex, tidHex, antenna, rssi) {
  const epcBytes = Buffer.from(epcHex, 'hex');
  const tidBytes = Buffer.from(tidHex ? tidHex : epcHex, 'hex'); // fallback to EPC if no TID
  const data = [
    0x00,                 // result = success
    antenna & 0xFF,       // antenna port (1-4)
    rssi & 0xFF,          // RSSI
    epcBytes.length,      // EPC length
    ...epcBytes,          // EPC
    tidBytes.length,      // TID length
    ...tidBytes,          // TID
  ];
  return buildFrame(CMD.TAG_DATA, data);
}

// ── State ─────────────────────────────────────────────────────────────────────
let activeTcpSockets = [];
let isReaderOnline = false;
let isMiddlewareReading = false;
let announceTimer = null;
let udpSocket = null;
let tcpServer = null;

const localIp = getLocalIpv4();
const fakeMac = buildFakeMac();

// ── UDP Multicast Announcer ───────────────────────────────────────────────────
function startDiscovery() {
  if (udpSocket) return;
  console.log('[UDP] Starting discovery announcer...');
  
  const announcement = Buffer.from(
    `^RFID_READER_INFORMATION:OpenRFID-Sim,IP:${localIp},MAC:${fakeMac},` +
    `PORT:${TCP_PORT},HOST_SERVER_IP:0.0.0.0,HOST_SERVER_PORT:0,` +
    `MODE:SERVER,NET_STATE:CONNECTED$`,
    'ascii'
  );

  udpSocket = dgram.createSocket({ type: 'udp4', reuseAddr: true });
  udpSocket.on('error', (err) => console.error('[UDP] Error:', err.message));
  
  udpSocket.bind(0, () => {
    try {
      udpSocket.setMulticastTTL(16);
      udpSocket.setMulticastLoopback(true);
    } catch (e) {
      console.error('[UDP] Multicast config error:', e.message);
    }
    
    const send = () => {
      if (udpSocket) {
        udpSocket.send(announcement, 0, announcement.length, MULTICAST_PORT, MULTICAST_GROUP);
      }
    };
    send();
    announceTimer = setInterval(send, ANNOUNCE_INTERVAL);
    console.log(`[UDP] Announcing on multicast ${MULTICAST_GROUP}:${MULTICAST_PORT} every ${ANNOUNCE_INTERVAL}ms`);
  });
}

function stopDiscovery() {
  console.log('[UDP] Stopping discovery announcer...');
  if (announceTimer) { clearInterval(announceTimer); announceTimer = null; }
  if (udpSocket) {
    try { udpSocket.close(); } catch (e) {}
    udpSocket = null;
  }
}

// ── TCP Server ────────────────────────────────────────────────────────────────
function startTcpServer() {
  if (tcpServer) return;
  console.log('[TCP] Starting command server...');
  
  tcpServer = net.createServer((socket) => {
    const remote = `${socket.remoteAddress}:${socket.remotePort}`;
    console.log(`[TCP] Connection from ${remote}`);
    activeTcpSockets.push(socket);
    
    let buf = Buffer.alloc(0);

    socket.on('data', (chunk) => {
      buf = Buffer.concat([buf, chunk]);
      while (buf.length >= 7) {
        if (buf[0] !== 0xAA) {
          const nextAA = buf.indexOf(0xAA, 1);
          if (nextAA === -1) { buf = Buffer.alloc(0); break; }
          buf = buf.slice(nextAA);
          continue;
        }
        if (buf.length < 5) break;
        const dataLen = (buf[3] << 8) | buf[4];
        const frameLen = 5 + dataLen + 2;
        if (buf.length < frameLen) break;

        const frame = buf.slice(0, frameLen);
        buf = buf.slice(frameLen);
        
        const cmd = frame[2];
        console.log(`[TCP] ← RX cmd=0x${cmd.toString(16).toUpperCase()} from ${remote}`);
        
        if (cmd === CMD.STOP) {
          socket.write(ackOk(CMD.STOP));
          isMiddlewareReading = false;
          console.log('[TCP] Reading stopped by middleware');
        } else if (cmd === CMD.GET_EPC) {
          socket.write(ackOk(CMD.GET_EPC));
          isMiddlewareReading = true;
          console.log('[TCP] Reading started by middleware');
        } else {
          socket.write(ackOk(cmd));
        }
      }
    });

    socket.on('close', () => {
      console.log(`[TCP] Connection closed: ${remote}`);
      activeTcpSockets = activeTcpSockets.filter(s => s !== socket);
      if (activeTcpSockets.length === 0) {
        isMiddlewareReading = false;
      }
    });

    socket.on('error', (err) => {
      console.error(`[TCP] Socket error: ${err.message}`);
    });
  });

  tcpServer.listen(TCP_PORT, '0.0.0.0', () => {
    console.log(`[TCP] Server listening on port ${TCP_PORT}`);
  });
}

function stopTcpServer() {
  console.log('[TCP] Stopping command server...');
  isMiddlewareReading = false;
  for (const socket of activeTcpSockets) {
    try { socket.destroy(); } catch (e) {}
  }
  activeTcpSockets = [];
  if (tcpServer) {
    try { tcpServer.close(); } catch (e) {}
    tcpServer = null;
  }
}

// ── WebSocket Bridge Server ───────────────────────────────────────────────────
console.log(`[WS] Starting bridge server on port ${WS_PORT}...`);
const wss = new ws.Server({ port: WS_PORT });

wss.on('connection', (wsConn) => {
  console.log('[WS] UI connected to bridge.');

  wsConn.on('message', (message) => {
    try {
      const data = JSON.parse(message);
      
      if (data.type === 'reader-status') {
        const online = data.status === 'ONLINE';
        console.log(`[WS] Reader status update: ${data.name} is ${data.status}`);
        
        if (online) {
          isReaderOnline = true;
          startDiscovery();
          startTcpServer();
        } else {
          isReaderOnline = false;
          stopDiscovery();
          stopTcpServer();
        }
      } 
      
      else if (data.type === 'tag-detected') {
        // Forward tag event to middleware if reading is active
        if (isMiddlewareReading && activeTcpSockets.length > 0) {
          const epcHex = data.epc;
          const tidHex = data.tid;
          const antenna = data.antennaId || 1;
          const rssi = Math.abs(Math.round(data.rssi || -55));
          
          const frame = buildTagFrame(epcHex, tidHex, antenna, rssi);
          for (const socket of activeTcpSockets) {
            if (!socket.destroyed) {
              socket.write(frame);
            }
          }
          console.log(`[WS] Forwarded tag ${epcHex} to middleware (ant=${antenna}, rssi=-${rssi})`);
        }
      }
    } catch (e) {
      console.error('[WS] Error processing message:', e.message);
    }
  });

  wsConn.on('close', () => {
    console.log('[WS] UI disconnected from bridge.');
  });
});

// ── Helper functions ──────────────────────────────────────────────────────────
function getLocalIpv4() {
  for (const list of Object.values(os.networkInterfaces())) {
    for (const e of (list || [])) {
      if (e.family === 'IPv4' && !e.internal) return e.address;
    }
  }
  return '127.0.0.1';
}

function buildFakeMac() {
  const hash = os.hostname().split('').reduce((h,c) => ((h<<5)-h+c.charCodeAt(0))|0, 0);
  const hex = Math.abs(hash+0x100000).toString(16).padStart(8,'0');
  return `52-46-${hex.slice(0,2)}-${hex.slice(2,4)}-${hex.slice(4,6)}-${hex.slice(6,8)}`.toUpperCase();
}

// ── Startup & Verification ────────────────────────────────────────────────────
console.log('╔══════════════════════════════════════════════════════════════╗');
console.log('║       OpenRFID Simulator — Hopeland Protocol Bridge          ║');
console.log('╚══════════════════════════════════════════════════════════════╝');
console.log(`  Local IP  : ${localIp}`);
console.log(`  Fake MAC  : ${fakeMac}`);
console.log(`  WS Bridge : ws://${localIp}:${WS_PORT}`);
console.log(`  TCP Server: ${localIp}:${TCP_PORT} (controlled by UI)`);
console.log(`  Discovery : UDP ${MULTICAST_GROUP}:${MULTICAST_PORT} (controlled by UI)\n`);

console.log('[CRC] Running self-test...');
let selfTestOk = true;
for (const { data, crc } of KNOWN_FRAMES) {
  const computed = calcCRC(data);
  const ok = computed[0] === crc[0] && computed[1] === crc[1];
  if (!ok) selfTestOk = false;
  console.log(`  ${ok?'✅':'❌'} [${data.map(b=>b.toString(16).toUpperCase().padStart(2,'0')).join(' ')}] → ${computed.map(b=>b.toString(16).toUpperCase().padStart(2,'0')).join(' ')}`);
}

if (!selfTestOk) {
  console.error('[CRC] ❌ Self-test failed. Please check the CRC algorithm.');
  process.exit(1);
} else {
  console.log('[CRC] ✅ Self-test passed.');
}

console.log('\nWaiting for browser simulation to start (Click "Start Simulation" in browser UI)...');

// ── Graceful Shutdown ─────────────────────────────────────────────────────────
process.on('SIGINT', () => {
  console.log('\n[INFO] Shutting down...');
  stopDiscovery();
  stopTcpServer();
  wss.close(() => {
    console.log('[INFO] Done.');
    process.exit(0);
  });
});
